1708→    @VisibleForTesting
1709→    inner class RenderOnScroll : AbsListView.OnScrollListener {
1710→        override fun onScroll(view: AbsListView, firstVisibleItem: Int, visibleItemCount: Int, totalItemCount: Int) {
1711→            // Show the progress bar if scrolling to given position requires rendering of the question / answer
1712→            val lastVisibleItem = firstVisibleItem + visibleItemCount - 1
1713→            // List is never cleared, only reset to a new list. So it's safe here.
1714→            val size = viewModel.rowCount
1715→            if (size > 0 && visibleItemCount <= 0) {
1716→                // According to Mike, there used to be 5 to 10 report by hour on the beta version. All with
1717→                // > com.ichi2.anki.exception.ManuallyReportedException: Useless onScroll call, with size 0 firstVisibleItem 0,
1718→                // > lastVisibleItem 0 and visibleItemCount 0.
1719→
1720→                // This change ensure that we log more specifically case where #8821 could have occurred. That is, there are cards but we
1721→                // are asked to display nothing.
1722→
1723→                // Note that this is not a bug. The fact that `visibleItemCount` is equal to 0 is actually authorized by the method we
1724→                // override and mentioned in the javadoc. It perfectly makes sens to get this order, since it can be used to know that we
1725→                // can delete some elements from the cache for example, since nothing is displayed.
1726→
1727→                // It would be interesting to know how often it occurs, but it is not a bug.
1728→                CrashReportService.sendExceptionReport("CardBrowser Scroll Issue 8821", "In a search result of $size cards, with totalItemCount = $totalItemCount, somehow we got $visibleItemCount elements to display.")
1729→            }
1730→            // In all of those cases, there is nothing to do:
1731→            if (size <= 0 || firstVisibleItem >= size || lastVisibleItem >= size || visibleItemCount <= 0) {
1732→                return
1733→            }
1734→            val firstLoaded = viewModel.getRowAtPosition(firstVisibleItem).isLoaded
1735→            // Note: max value of lastVisibleItem is totalItemCount, so need to subtract 1
1736→            val lastLoaded = viewModel.getRowAtPosition(lastVisibleItem).isLoaded
1737→            if (!firstLoaded || !lastLoaded) {
1738→                if (!mPostAutoScroll) {
1739→                    showProgressBar()
1740→                }
1741→                // Also start rendering the items on the screen every 300ms while scrolling
1742→                val currentTime = SystemClock.elapsedRealtime()
1743→                if (currentTime - mLastRenderStart > 300 || lastVisibleItem + 1 >= totalItemCount) {
1744→                    mLastRenderStart = currentTime
1745→                    renderBrowserQAJob?.cancel()
1746→                    launchCatchingTask { renderBrowserQAParams(firstVisibleItem, visibleItemCount, mCards.toList()) }
1747→                }
1748→            }
1749→        }
1750→
1751→        override fun onScrollStateChanged(listView: AbsListView, scrollState: Int) {
1752→            // TODO: Try change to RecyclerView as currently gets stuck a lot when using scrollbar on right of ListView
1753→            // Start rendering the question & answer every time the user stops scrolling
1754→            if (mPostAutoScroll) {
1755→                mPostAutoScroll = false
1756→            }
1757→            if (scrollState == AbsListView.OnScrollListener.SCROLL_STATE_IDLE) {
1758→                val startIdx = listView.firstVisiblePosition
1759→                val numVisible = listView.lastVisiblePosition - startIdx
1760→                launchCatchingTask { renderBrowserQAParams(startIdx - 5, 2 * numVisible + 5, mCards.toList()) }
1761→            }
1762→        }
1763→    }
