1766→    protected suspend fun renderBrowserQAParams(firstVisibleItem: Int, visibleItemCount: Int, cards: List<CardCache>) {
1767→        Timber.d("Starting Q&A background rendering")
1768→        val result = renderBrowserQA(
1769→            cards,
1770→            firstVisibleItem,
1771→            visibleItemCount,
1772→            viewModel.column1Index,
1773→            viewModel.column2Index
1774→        ) {
1775→            // Note: This is called every time a card is rendered.
1776→            // It blocks the long-click callback while the task is running, so usage of the task should be minimized
1777→            cardsAdapter.notifyDataSetChanged()
1778→        }
1779→        onPostExecuteRenderBrowserQA(result)
