1935→    /** A position-aware collection to ensure consistency between the position of items and the collection  */
1936→    class CardCollection<T : PositionAware?> : Iterable<T> {
1937→        var wrapped: MutableList<T> = ArrayList(0)
1938→            private set
1939→        fun size(): Int {
1940→            return wrapped.size
1941→        }
1942→
1943→        operator fun get(index: Int): T {
