1956→            wrapped.reverse()
1957→            wrapped.forEachIndexed { pos, card -> card!!.position = pos }
1958→        }
1959→
1960→        override fun iterator(): MutableIterator<T> {
1961→            return wrapped.iterator()
1962→        }
1963→
1964→        fun clear() {
1965→            wrapped.clear()
1966→        }
1967→    }
