2092→        /** pre compute the note and question/answer.  It can safely
2093→         * be called twice without doing extra work.  */
2094→        fun load(reload: Boolean, column1Index: Int, column2Index: Int) {
2095→            if (reload) {
2096→                reload()
2097→            }
2098→            card.note()
2099→            // First column can not be the answer. If it were to change, this code should also be changed.
2100→            if (COLUMN1_KEYS[column1Index] == Column.QUESTION || arrayOf(Column.QUESTION, Column.ANSWER).contains(COLUMN2_KEYS[column2Index])) {
2101→                updateSearchItemQA()
2102→            }
2103→            isLoaded = true
2104→        }
