1792→        override fun getView(position: Int, convertView: View?, parent: ViewGroup): View {
1793→            // Get the main container view if it doesn't already exist, and call bindView
1794→            val v: View
1795→            if (convertView == null) {
1796→                v = mInflater.inflate(resource, parent, false)
1797→                val count = toIds.size
1798→                val columns = arrayOfNulls<View>(count)
1799→                for (i in 0 until count) {
1800→                    columns[i] = v.findViewById(toIds[i])
1801→                }
