1810→        @Suppress("UNCHECKED_CAST")
1811→        @KotlinCleanup("Unchecked cast")
1812→        private fun bindView(position: Int, v: View) {
1813→            // Draw the content in the columns
1814→            val card = getItem(position)
1815→            (v.tag as Array<*>)
1816→                .forEachIndexed { i, col ->
1817→                    setFont(col as TextView) // set font for column
1818→                    col.text = card.getColumnHeaderText(fromKeys[i]) // set text for column
1819→                }
1820→            // set card's background color
1821→            val backgroundColor: Int = MaterialColors.getColor(this@CardBrowser, card.color, 0)
1822→            v.setBackgroundColor(backgroundColor)
1823→            // setup checkbox to change color in multi-select mode
1824→            val checkBox = v.findViewById<CheckBox>(R.id.card_checkbox)
1825→            // if in multi-select mode, be sure to show the checkboxes
1826→            if (isInMultiSelectMode) {
1827→                checkBox.visibility = View.VISIBLE
1828→                checkBox.isChecked = viewModel.selectedRows.contains(card)
1829→                // this prevents checkboxes from showing an animation from selected -> unselected when
1830→                // checkbox was selected, then selection mode was ended and now restarted
1831→                checkBox.jumpDrawablesToCurrentState()
1832→            } else {
1833→                checkBox.isChecked = false
1834→                checkBox.visibility = View.GONE
1835→            }
1836→            // change bg color on check changed
1837→            checkBox.setOnClickListener { viewModel.toggleRowSelectionAtPosition(position) }
1838→            val column1 = v.findViewById<FixedTextView>(R.id.card_sfld)
1839→            val column2 = v.findViewById<FixedTextView>(R.id.card_column2)
1840→
1841→            if (viewModel.isTruncated) {
1842→                column1.maxLines = LINES_VISIBLE_WHEN_COLLAPSED
1843→                column2.maxLines = LINES_VISIBLE_WHEN_COLLAPSED
1844→                column1.ellipsize = TextUtils.TruncateAt.END
