1855→            if (mOriginalTextSize < 0) {
1856→                mOriginalTextSize = v.textSize
1857→            }
1858→            // do nothing when pref is 100% and apply scaling only once
1859→            if (fontSizeScalePcent != 100 && abs(mOriginalTextSize - currentSize) < 0.1) {
1860→                // getTextSize returns value in absolute PX so use that in the setter
1861→                v.setTextSize(TypedValue.COMPLEX_UNIT_PX, mOriginalTextSize * (fontSizeScalePcent / 100.0f))
