2106→        /**
2107→         * Reload question and answer. Use browser format. If it's empty
2108→         * uses non-browser format. If answer starts by question, remove
2109→         * question.
2110→         */
2111→        private fun updateSearchItemQA() {
2112→            if (mQa != null) {
2113→                return
2114→            }
2115→            // render question and answer
2116→            val qa = card.renderOutput(reload = true, browser = true)
2117→            // Render full question / answer if the bafmt (i.e. "browser appearance") setting forced blank result
2118→            if (qa.questionText.isEmpty() || qa.answerText.isEmpty()) {
2119→                val (question_text, answer_text) = card.renderOutput(
2120→                    reload = true,
2121→                    browser = false
2122→                )
2123→                if (qa.questionText.isEmpty()) {
2124→                    qa.questionText = question_text
2125→                }
2126→                if (qa.answerText.isEmpty()) {
2127→                    qa.answerText = answer_text
2128→                }
2129→            }
2130→            // update the original hash map to include rendered question & answer
2131→            var q = qa.questionText
2132→            var a = qa.answerText
2133→            // remove the question from the start of the answer if it exists
2134→            if (a.startsWith(q)) {
2135→                a = a.substring(q.length)
2136→            }
2137→            a = formatQA(a, AnkiDroidApp.instance)
2138→            q = formatQA(q, AnkiDroidApp.instance)
2139→            mQa = Pair(q, a)
2140→        }
